CommandResult handleLspStartAll(const CommandContext& ctx) {
    auto& lsp = LspClientBridge::instance();
    if (lsp.isActive()) return CommandResult::error("LSP already running");
    
    std::vector<std::string> servers = {"clangd", "pylsp", "tsserver", "rust-analyzer"};
    int started = 0;
    for (auto& svr : servers) {
        if (lsp.startServer(svr)) started++;
    }
    return started > 0 
        ? CommandResult::ok(("Started " + std::to_string(started) + " LSP servers").c_str())
        : CommandResult::error("Failed to start any LSP servers");
}

