// SubAgent (Real Multi-Agent Coordination)
CommandResult handleSubAgentChain(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("subagent.chain", "Usage: !chain <agent1> <agent2> ...");
    }
    
    std::vector<std::string> agents;
    std::stringstream ss(ctx.args);
    std::string agent;
    while (ss >> agent) agents.push_back(agent);
    
    ctx.output(("Chaining " + std::to_string(agents.size()) + " agents...\n").c_str());
    
    for (size_t i = 0; i < agents.size(); i++) {
        ctx.output(("  [" + std::to_string(i) + "] " + agents[i] + "\n").c_str());
        SubsystemParams params;
        params.set("agent", agents[i]);
        params.set("chain_position", std::to_string(i));
        SubsystemAgentBridge::instance().executeAction("ChainAgent", params);
    }
    return CommandResult::ok("subagent.chain");
}

